"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[31241],{82575(e,t,a){a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>n,default:()=>u,frontMatter:()=>s,metadata:()=>o,toc:()=>c});const o=JSON.parse('{"id":"UserGuide/C21_Metrology/S01_Metrology_module","title":"Aurora Imaging Library Metrology module","description":"Many industries require the ability to measure and validate objects to, for example, assemble multiple parts. Historically, in such industries, manual quality control applications were created to verify the shape, size, and location of objects relative to one another. To accomplish this, a template was used. A template is a physical part, or mold, that typically contains holes and incisions at various positions. If the object being verified physically fit into the template, then that object had passed the quality inspection and could be used in assembly; otherwise, it had failed and would be discarded or reworked. The Aurora Imaging Library Metrology module is a powerful set of functions that allows you to design such measurement and validation applications, using a virtual equivalent of a physical template.","source":"@site/docs/UserGuide/C21_Metrology/S01_Metrology_module.md","sourceDirName":"UserGuide/C21_Metrology","slug":"/UserGuide/C21_Metrology/S01_Metrology_module","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C21_Metrology/S01_Metrology_module","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"doctype":"UserGuide","part":"2D processing and analysis","chapter":"Metrology","section":"Metrology_module","module_tag":"met","product":"Aurora-Imaging-Library-user-guide","version":1100,"path":"UserGuide / 2D processing and analysis / metrology / Metrology module"},"sidebar":"userGuideSidebar","previous":{"title":"Metrology","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C21_Metrology/ChapterInformation"},"next":{"title":"Steps to measure and validate expected features","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C21_Metrology/S02_Steps_to_measure_and_validate_expected_features"}}');var r=a(74848),i=a(28453);const s={doctype:"UserGuide",part:"2D processing and analysis",chapter:"Metrology",section:"Metrology_module",module_tag:"met",product:"Aurora-Imaging-Library-user-guide",version:1100,path:"UserGuide / 2D processing and analysis / metrology / Metrology module"},n="Aurora Imaging Library Metrology module",l={},c=[];function d(e){const t={a:"a",blockquote:"blockquote",em:"em",h1:"h1",header:"header",p:"p",strong:"strong",...(0,i.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(t.header,{children:(0,r.jsx)(t.h1,{id:"aurora-imaging-library-metrology-module",children:"Aurora Imaging Library Metrology module"})}),"\n",(0,r.jsx)(t.p,{children:"Many industries require the ability to measure and validate objects to, for example, assemble multiple parts. Historically, in such industries, manual quality control applications were created to verify the shape, size, and location of objects relative to one another. To accomplish this, a template was used. A template is a physical part, or mold, that typically contains holes and incisions at various positions. If the object being verified physically fit into the template, then that object had passed the quality inspection and could be used in assembly; otherwise, it had failed and would be discarded or reworked. The Aurora Imaging Library Metrology module is a powerful set of functions that allows you to design such measurement and validation applications, using a virtual equivalent of a physical template."}),"\n",(0,r.jsx)(t.p,{children:"The Aurora Imaging Library metrology template represents a precisely measured and reusable model from which objects can be verified and measured. To build a metrology template, you must have features (which are like the holes and incisions) and geometric tolerances (which are like the positions that features must have, relative to other features)."}),"\n",(0,r.jsx)(t.p,{children:"You can add either physically measured or constructed features to your metrology template. Physically measured features are geometric primitives (such as a circle) that are physically measured using the edge information (edgels) in the target image. Physically measured features, and the metrology region (ROI) from which their edgels are established in the target image, must be placed at the appropriate location in the template."}),"\n",(0,r.jsxs)(t.p,{children:["Note that Metrology's edgel extraction is based on Edge Finder technology; for more information, see ",(0,r.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C10_Edge_Finder/S04_Extracting_the_edges",children:"Extracting the edges"}),"."]}),"\n",(0,r.jsx)(t.p,{children:"Constructed features are geometric primitives that do not actually exist in the target image, they are mathematically defined (parametrically constructed features) or geometrically derived from a set of other features (either constructed or physically measured). For example, a constructed point feature can be derived at the center of a physically measured circle."}),"\n",(0,r.jsx)(t.p,{children:"Features alone do not typically provide enough information to establish the metrology template. For example, if you add two segment features, you might also want to verify their total length, or if they are perpendicular. To do this, you can specify the geometric tolerances that the features of the object in the target image must respect to be considered valid."}),"\n",(0,r.jsx)(t.p,{children:"The following example illustrates how you can use features and geometric tolerances in a metrology template to represent an appropriate object in a target image. To depict this object, the template has two ring-shaped metrology regions where two circles are expected to be physically measured, and one rectangular metrology region where one segment is expected to be physically measured. The template also contains the definition of a constructed segment, built from the center points of the two physically measured circles, and a perpendicularity tolerance between this constructed segment and the physically measured segment. The following example also shows the target image, which has been annotated to display the successfully measured features and the validated tolerance."}),"\n",(0,r.jsx)(t.p,{children:(0,r.jsx)(t.em,{children:"[Image: Metro_GD_T01_Intro.png]"})}),"\n",(0,r.jsx)(t.p,{children:"The Aurora Imaging Library Metrology module allows you to specify the coordinates of features and metrology regions relative to a reference frame, which can be set to either the global frame or a local frame."}),"\n",(0,r.jsx)(t.p,{children:"The global frame is a coordinate system whose origin is at the top-left corner of the metrology template (by default, aligned with the center of the top-left corner pixel of the target image); the global frame is created automatically. A local frame is a coordinate system that can be located anywhere within the metrology template; you can create a local frame at a specified position or based on the positions of other features in the template. During calculation, the reference frame can be repositioned."}),"\n",(0,r.jsx)(t.p,{children:"The Aurora Imaging Library Metrology module provides complete support for camera calibration. If the target image is calibrated, calculations are performed in the calibrated real-world such that, without physically correcting your images, measurements and calculations are made even in the presence of distortion, and results calculated in real-world units."}),"\n",(0,r.jsx)(t.p,{children:"Note that, when complex distortions exist, some results are meaningless when converted from real-world to pixel units (for example, angle). You should therefore be cautious when using distorted images."}),"\n",(0,r.jsxs)(t.blockquote,{children:["\n",(0,r.jsxs)(t.p,{children:[(0,r.jsx)(t.strong,{children:"Note:"})," If a camera calibration context has been associated with the target image, you must specify dimensions for features, geometric tolerances, metrology regions, and positions in real-world units."]}),"\n"]}),"\n",(0,r.jsx)(t.p,{children:"The Aurora Imaging Library Metrology module also allows you to restore a metrology context from a file or memory stream, or save a metrology context to a file or memory stream."})]})}function u(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,r.jsx)(t,{...e,children:(0,r.jsx)(d,{...e})}):d(e)}},28453(e,t,a){a.d(t,{R:()=>s,x:()=>n});var o=a(96540);const r={},i=o.createContext(r);function s(e){const t=o.useContext(i);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function n(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:s(e.components),o.createElement(i.Provider,{value:t},e.children)}}}]);